package codex

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"os"
	osexec "os/exec"
	"strings"
	"syscall"
	"time"

	"github.com/easel/fizeau/internal/harnesses"
	"github.com/easel/fizeau/internal/modelcatalog"
)

const defaultEventBuffer = 64

// Fallback only: unpinned runs resolve through model discovery first.
const fallbackDefaultModel = "gpt-5.4"

// Runner is the subprocess-backed codex harness. It launches codex in
// exec --json mode, parses each JSONL line into harness Events, and emits
// a final Event when the subprocess exits.
type Runner struct {
	// Binary is the absolute path to the codex executable. When empty the
	// runner resolves "codex" via PATH at Execute time.
	Binary string

	// BaseArgs is prepended to the per-request argument list.
	// Codex default: ["exec", "--json"]
	BaseArgs []string

	// PromptMode controls how the prompt is delivered:
	//   "arg" (default) — prompt is appended as the final positional argument
	//   "stdin"         — prompt is piped on stdin
	PromptMode string

	// EventBuffer overrides the per-Execute channel buffer size.
	EventBuffer int

	// DiscoveryCache overrides model/reasoning discovery evidence in tests.
	DiscoveryCache *harnesses.ModelDiscoveryCache
}

// Info returns identity + capability metadata for this harness.
func (r *Runner) Info() harnesses.HarnessInfo {
	info := harnesses.HarnessInfo{
		Name:                 "codex",
		Type:                 "subprocess",
		IsLocal:              false,
		IsSubscription:       true,
		AutoRoutingEligible:  true,
		ExactPinSupport:      true,
		DefaultModel:         harnesses.ResolveRunnerModel("codex", modelcatalog.SurfaceCodex, "", fallbackDefaultModel).ResolvedModel,
		SupportedPermissions: []string{"safe", "supervised", "unrestricted"},
		SupportedReasoning:   []string{"low", "medium", "high", "xhigh", "max"},
		CostClass:            "medium",
	}
	path := r.Binary
	if path == "" {
		if resolved, err := osexec.LookPath("codex"); err == nil {
			path = resolved
		}
	}
	if path != "" {
		info.Path = path
		info.Available = true
	} else {
		info.Error = "codex binary not found in PATH"
	}
	return info
}

// HealthCheck verifies the codex binary is present.
func (r *Runner) HealthCheck(ctx context.Context) error {
	if err := ctx.Err(); err != nil {
		return err
	}
	path := r.Binary
	if path == "" {
		resolved, err := osexec.LookPath("codex")
		if err != nil {
			return fmt.Errorf("codex binary not found: %w", err)
		}
		path = resolved
	}
	st, err := os.Stat(path)
	if err != nil {
		return fmt.Errorf("stat codex binary: %w", err)
	}
	if st.IsDir() {
		return fmt.Errorf("codex binary path is a directory: %s", path)
	}
	return nil
}

// Execute runs one resolved request through the codex CLI and emits
// JSONL-derived events on the returned channel.
func (r *Runner) Execute(ctx context.Context, req harnesses.ExecuteRequest) (<-chan harnesses.Event, error) {
	binary := r.Binary
	if binary == "" {
		resolved, err := osexec.LookPath("codex")
		if err != nil {
			return nil, fmt.Errorf("codex binary not found: %w", err)
		}
		binary = resolved
	}

	bufSize := r.EventBuffer
	if bufSize <= 0 {
		bufSize = defaultEventBuffer
	}

	out := make(chan harnesses.Event, bufSize)
	go r.run(ctx, binary, req, out)
	return out, nil
}

func (r *Runner) run(ctx context.Context, binary string, req harnesses.ExecuteRequest, out chan<- harnesses.Event) {
	defer close(out)

	start := time.Now()
	var seq int64

	agg, exitCode, stderr, runErr, status := r.runStreaming(ctx, binary, req, out, &seq)

	final := harnesses.FinalData{
		Status:     status,
		ExitCode:   exitCode,
		DurationMS: time.Since(start).Milliseconds(),
	}
	reasoningResolution := harnesses.ResolveRunnerReasoningWithCache(r.DiscoveryCache, "codex", req.Reasoning)
	if harnesses.ShouldEmitRunnerReasoningResolution(reasoningResolution) {
		final.Reasoning = &reasoningResolution
	}
	if runErr != nil && status != "success" {
		final.Error = runErr.Error()
	} else if stderr != "" && status != "success" {
		final.Error = trimErrorBlob(stderr)
	}
	if agg != nil {
		final.FinalText = agg.FinalText
		final.Usage, final.Warnings = harnesses.ResolveFinalUsage(agg.UsageSources)
		agg.writeTokenCountQuotaCache()
	}

	finalRaw, err := json.Marshal(final)
	if err != nil {
		finalRaw = []byte(`{"status":"failed","error":"marshal final event"}`)
	}
	ev := harnesses.Event{
		Type:     harnesses.EventTypeFinal,
		Sequence: seq,
		Time:     time.Now().UTC(),
		Metadata: req.Metadata,
		Data:     finalRaw,
	}
	select {
	case out <- ev:
	case <-time.After(time.Second):
	}
}

func (a *streamAggregate) writeTokenCountQuotaCache() {
	if a == nil || len(a.TokenCountRateLimits) == 0 {
		return
	}
	var newest *CodexQuotaSnapshot
	for _, evidence := range a.TokenCountRateLimits {
		fallback := time.Now().UTC()
		snapshot, ok := CodexQuotaSnapshotFromTokenCountRateLimits(evidence.CapturedAt, fallback, evidence.RateLimits)
		if !ok {
			continue
		}
		snapshot.Source = "codex_exec_token_count"
		if newest == nil || snapshot.CapturedAt.After(newest.CapturedAt) {
			newest = snapshot
		}
	}
	if newest == nil {
		return
	}
	path, err := CodexQuotaCachePath()
	if err != nil {
		return
	}
	_ = WriteCodexQuota(path, *newest)
}

func (r *Runner) runStreaming(ctx context.Context, binary string, req harnesses.ExecuteRequest, out chan<- harnesses.Event, seq *int64) (agg *streamAggregate, exitCode int, stderr string, runErr error, status string) {
	base := r.BaseArgs
	if base == nil {
		base = []string{"exec", "--json"}
	}
	args := append([]string{}, base...)
	modelResolution := harnesses.ResolveRunnerModelWithCache(r.DiscoveryCache, "codex", modelcatalog.SurfaceCodex, req.Model, fallbackDefaultModel)
	reasoningResolution := harnesses.ResolveRunnerReasoningWithCache(r.DiscoveryCache, "codex", req.Reasoning)

	// Permission args: unrestricted adds --dangerously-bypass-approvals-and-sandbox
	if req.Permissions == "unrestricted" {
		args = append(args, "--dangerously-bypass-approvals-and-sandbox")
	}

	// WorkDir flag: -C <dir>
	if req.WorkDir != "" {
		args = append(args, "-C", req.WorkDir)
	}

	// Model flag: -m <model>
	if modelResolution.ResolvedModel != "" {
		args = append(args, "-m", modelResolution.ResolvedModel)
	}

	// Reasoning flag: -c reasoning.effort=<reasoning>
	if value := reasoningResolution.ResolvedReasoning; value != "" {
		args = append(args, "-c", fmt.Sprintf("reasoning.effort=%s", value))
	}

	promptMode := r.PromptMode
	if promptMode == "" {
		promptMode = "arg"
	}
	if promptMode == "arg" && req.Prompt != "" {
		args = append(args, req.Prompt)
	}

	runCtx, cancel := context.WithCancel(ctx)
	defer cancel()

	cmd := harnesses.HarnessCommand(runCtx, binary, args...)
	if req.WorkDir != "" {
		cmd.Dir = req.WorkDir
	}
	if promptMode != "arg" {
		cmd.Stdin = strings.NewReader(req.Prompt)
	}
	setProcessGroup(cmd)

	stdoutPipe, err := cmd.StdoutPipe()
	if err != nil {
		return nil, -1, "", err, "failed"
	}
	stderrPipe, err := cmd.StderrPipe()
	if err != nil {
		return nil, -1, "", err, "failed"
	}

	if err := cmd.Start(); err != nil {
		return nil, -1, "", err, "failed"
	}

	progressLog, _ := harnesses.OpenProgressLog(req.SessionLogDir, req.SessionID, "codex")
	if progressLog != nil {
		defer progressLog.Close()
	}
	if harnesses.ShouldEmitRunnerDefaultResolution(modelResolution) {
		ev := harnesses.RunnerDefaultResolutionEvent(modelResolution, req.Metadata, seq)
		harnesses.WriteProgressEvent(progressLog, ev)
		select {
		case out <- ev:
		case <-ctx.Done():
			return nil, -1, "", ctx.Err(), "cancelled"
		}
	}
	if harnesses.ShouldEmitRunnerReasoningResolution(reasoningResolution) {
		harnesses.LogRunnerReasoningWarning(reasoningResolution)
		ev := harnesses.RunnerReasoningResolutionEvent(reasoningResolution, req.Metadata, seq)
		harnesses.WriteProgressEvent(progressLog, ev)
		select {
		case out <- ev:
		case <-ctx.Done():
			return nil, -1, "", ctx.Err(), "cancelled"
		}
	}

	parserReader, parserWriter := io.Pipe()
	parseDone := make(chan struct{})
	var parseAgg *streamAggregate
	var parseErr error
	go func() {
		defer close(parseDone)
		mirrored, mirrorDone := harnesses.MirrorEvents(out, progressLog, ctx)
		defer func() {
			close(mirrored)
			<-mirrorDone
		}()
		parseAgg, parseErr = parseCodexStream(runCtx, parserReader, mirrored, req.Metadata, seq)
	}()

	stdoutDone := make(chan struct{})
	go func() {
		defer close(stdoutDone)
		_, _ = io.Copy(parserWriter, stdoutPipe)
		_ = parserWriter.Close()
	}()

	var stderrBuf strings.Builder
	stderrDone := make(chan struct{})
	go func() {
		defer close(stderrDone)
		_, _ = io.Copy(&stringBuilderWriter{&stderrBuf}, stderrPipe)
	}()

	var timedOut bool
	if req.Timeout > 0 {
		stop := make(chan struct{})
		go func() {
			select {
			case <-stop:
			case <-time.After(req.Timeout):
				timedOut = true
				cancel()
			}
		}()
		defer close(stop)
	}

	cancelDone := make(chan struct{})
	go func() {
		defer close(cancelDone)
		select {
		case <-ctx.Done():
			killProcessGroup(cmd)
		case <-stdoutDone:
		}
	}()

	<-stdoutDone
	<-stderrDone
	<-parseDone
	runErr = cmd.Wait()
	<-cancelDone
	stderr = stderrBuf.String()

	switch {
	case timedOut:
		return parseAgg, -1, stderr, context.DeadlineExceeded, "timed_out"
	case ctx.Err() != nil && errors.Is(ctx.Err(), context.Canceled):
		return parseAgg, -1, stderr, ctx.Err(), "cancelled"
	case ctx.Err() != nil && errors.Is(ctx.Err(), context.DeadlineExceeded):
		return parseAgg, -1, stderr, ctx.Err(), "timed_out"
	case runErr != nil:
		ec := -1
		var exitErr *osexec.ExitError
		if errors.As(runErr, &exitErr) {
			ec = exitErr.ExitCode()
		}
		return parseAgg, ec, stderr, runErr, "failed"
	}
	if parseErr != nil && !errors.Is(parseErr, context.Canceled) {
		return parseAgg, 0, stderr, parseErr, "failed"
	}
	return parseAgg, 0, stderr, nil, "success"
}

type stringBuilderWriter struct {
	sb *strings.Builder
}

func (w *stringBuilderWriter) Write(p []byte) (int, error) {
	return w.sb.Write(p)
}

func trimErrorBlob(s string) string {
	const max = 2048
	s = strings.TrimSpace(s)
	if len(s) > max {
		return s[:max] + "...(truncated)"
	}
	return s
}

func setProcessGroup(cmd *osexec.Cmd) {
	if cmd.SysProcAttr == nil {
		cmd.SysProcAttr = &syscall.SysProcAttr{}
	}
	setProcessGroupAttr(cmd.SysProcAttr)
}

1	package codex
2	
3	import (
4		"encoding/json"
5		"fmt"
6		"os"
7		"path/filepath"
8		"time"
9	
10		"github.com/easel/fizeau/internal/harnesses"
11		"github.com/easel/fizeau/internal/productinfo"
12		"github.com/easel/fizeau/internal/safefs"
13	)
14	
15	// CodexQuotaSnapshot captures Codex subscription quota windows in a durable
16	// cache so foreground service status calls do not need to spawn a live PTY probe.
17	type CodexQuotaSnapshot struct {
18		CapturedAt time.Time               `json:"captured_at"`
19		Windows    []harnesses.QuotaWindow `json:"windows"`
20		Source     string                  `json:"source"`
21		Account    *harnesses.AccountInfo  `json:"account,omitempty"`
22	}
23	
24	const DefaultCodexQuotaStaleAfter = 15 * time.Minute
25	
26	const codexQuotaCacheEnv = "FIZEAU_CODEX_QUOTA_CACHE"
27	
28	// CodexQuotaCachePath returns the durable location for the Codex quota cache.
29	func CodexQuotaCachePath() (string, error) {
30		if path := os.Getenv(codexQuotaCacheEnv); path != "" {
31			return path, nil
32		}
33		if xdg := os.Getenv("XDG_STATE_HOME"); xdg != "" {
34			return filepath.Join(xdg, productinfo.ConfigDir, "codex-quota.json"), nil
35		}
36		home, err := os.UserHomeDir()
37		if err != nil {
38			return "", err
39		}
40		return filepath.Join(home, ".local", "state", productinfo.ConfigDir, "codex-quota.json"), nil
41	}
42	
43	// WriteCodexQuota atomically persists a CodexQuotaSnapshot to path.
44	func WriteCodexQuota(path string, snapshot CodexQuotaSnapshot) error {
45		if path == "" {
46			return fmt.Errorf("codex quota cache path is empty")
47		}
48		if snapshot.CapturedAt.IsZero() {
49			snapshot.CapturedAt = time.Now().UTC()
50		} else {
51			snapshot.CapturedAt = snapshot.CapturedAt.UTC()
52		}
53		if snapshot.Source == "" {
54			snapshot.Source = "pty"
55		}
56		if snapshot.Account == nil {
57			if account, ok := ReadCodexAccount(); ok {
58				snapshot.Account = account
59			}
60		}
61		if err := os.MkdirAll(filepath.Dir(path), 0o750); err != nil {
62			return fmt.Errorf("create codex quota cache dir: %w", err)
63		}
64		data, err := json.MarshalIndent(snapshot, "", "  ")
65		if err != nil {
66			return fmt.Errorf("marshal codex quota snapshot: %w", err)
67		}
68		data = append(data, '\n')
69		tmpPath := path + ".tmp"
70		if err := os.WriteFile(tmpPath, data, 0o600); err != nil {
71			return fmt.Errorf("write codex quota cache tmp: %w", err)
72		}
73		if err := os.Rename(tmpPath, path); err != nil {
74			_ = os.Remove(tmpPath)
75			return fmt.Errorf("rename codex quota cache: %w", err)
76		}
77		if err := os.Chmod(path, 0o600); err != nil {
78			return fmt.Errorf("chmod codex quota cache: %w", err)
79		}
80		return nil
81	}
82	
83	// ReadCodexQuotaFrom reads one Codex quota snapshot.
84	func ReadCodexQuotaFrom(path string) (*CodexQuotaSnapshot, bool) {
85		data, err := safefs.ReadFile(path)
86		if err != nil {
87			return nil, false
88		}
89		var snap CodexQuotaSnapshot
90		if err := json.Unmarshal(data, &snap); err != nil {
91			return nil, false
92		}
93		return &snap, true
94	}
95	
96	// ReadCodexQuota reads the default Codex quota cache.
97	func ReadCodexQuota() (*CodexQuotaSnapshot, bool) {
98		path, err := CodexQuotaCachePath()
99		if err != nil {
100			return nil, false
101		}
102		return ReadCodexQuotaFrom(path)
103	}
104	
105	// CodexQuotaSnapshotAge reports snapshot age relative to now.
106	func CodexQuotaSnapshotAge(snapshot *CodexQuotaSnapshot, now time.Time) time.Duration {
107		if snapshot == nil || snapshot.CapturedAt.IsZero() {
108			return 0
109		}
110		age := now.UTC().Sub(snapshot.CapturedAt.UTC())
111		if age < 0 {
112			return 0
113		}
114		return age
115	}
116	
117	// IsCodexQuotaFresh reports whether a snapshot is present and fresh.
118	func IsCodexQuotaFresh(snapshot *CodexQuotaSnapshot, now time.Time, staleAfter time.Duration) bool {
119		if snapshot == nil || snapshot.CapturedAt.IsZero() {
120			return false
121		}
122		if staleAfter <= 0 {
123			staleAfter = DefaultCodexQuotaStaleAfter
124		}
125		return CodexQuotaSnapshotAge(snapshot, now) <= staleAfter
126	}
127	
128	// CodexQuotaRoutingDecision summarises whether foreground routing may select
129	// Codex without probing the CLI inline.
130	type CodexQuotaRoutingDecision struct {
131		PreferCodex     bool
132		SnapshotPresent bool
133		Fresh           bool
134		Age             time.Duration
135		Snapshot        *CodexQuotaSnapshot
136		Reason          string
137	}
138	
139	// DecideCodexQuotaRouting turns a durable quota snapshot into a foreground
140	// routing decision. Missing, stale, empty, or blocked quota evidence keeps
141	// Codex out of automatic routing; explicit Harness=codex remains available.
142	func DecideCodexQuotaRouting(snapshot *CodexQuotaSnapshot, now time.Time, staleAfter time.Duration) CodexQuotaRoutingDecision {
143		decision := CodexQuotaRoutingDecision{Snapshot: snapshot}
144		if snapshot == nil {
145			decision.Reason = "no cached snapshot; assume limited"
146			return decision
147		}
148		decision.SnapshotPresent = true
149		decision.Age = CodexQuotaSnapshotAge(snapshot, now)
150		if !IsCodexQuotaFresh(snapshot, now, staleAfter) {
151			decision.Reason = "cached snapshot is stale; assume limited"
152			return decision
153		}
154		decision.Fresh = true
155		if len(snapshot.Windows) == 0 {
156			decision.Reason = "fresh snapshot has no quota windows; assume limited"
157			return decision
158		}
159		if !codexAccountSupportsAutoRouting(snapshot.Account) {
160			decision.Reason = "fresh snapshot has no subsidized account plan; assume limited"
161			return decision
162		}
163		for _, window := range snapshot.Windows {
164			if window.State == "blocked" || window.UsedPercent >= 95 {
165				decision.Reason = "fresh snapshot reports blocked window; assume limited"
166				return decision
167			}
168		}
169		decision.PreferCodex = true
170		decision.Reason = "fresh snapshot has headroom"
171		return decision
172	}
173	
174	// ReadCodexQuotaRoutingDecision reads the default cache and produces a routing
175	// decision in one call.
176	func ReadCodexQuotaRoutingDecision(now time.Time, staleAfter time.Duration) CodexQuotaRoutingDecision {
177		snap, _ := ReadCodexQuota()
178		return DecideCodexQuotaRouting(snap, now, staleAfter)
179	}
