95	func codexDiscoveryFromText(text, source string) harnesses.ModelDiscoverySnapshot {
96		snapshot := DefaultCodexModelDiscovery()
97		if source != "" {
98			snapshot.Source = source
99		}
100		if models := parseCodexModels(text); len(models) > 0 {
