258	func codexQuotaSnapshotFromTokenCountRateLimits(raw json.RawMessage) ([]harnesses.QuotaWindow, *harnesses.AccountInfo, bool) {
259		var obj map[string]json.RawMessage
260		if err := json.Unmarshal(raw, &obj); err != nil {
261			return nil, nil, false
262		}
263		var windows []harnesses.QuotaWindow
264		keys := make([]string, 0, len(obj))
265		for key := range obj {
266			keys = append(keys, key)
267		}
268		sort.Strings(keys)
269		for _, key := range keys {
270			window, ok := codexQuotaWindowFromRaw(obj[key])
271			if ok {
272				windows = append(windows, window)
273			}
274		}
275		if len(windows) == 0 {
276			return nil, nil, false
277		}
278		var account *harnesses.AccountInfo
279		if plan := stringFromRaw(obj["plan_type"]); plan != "" {
280			account = &harnesses.AccountInfo{PlanType: normalizeCodexPlanType(plan)}
281		}
282		return windows, account, true
283	}
284	
285	func codexQuotaWindowFromRaw(raw json.RawMessage) (harnesses.QuotaWindow, bool) {
286		var obj map[string]json.RawMessage
287		if err := json.Unmarshal(raw, &obj); err != nil || obj == nil {
288			return harnesses.QuotaWindow{}, false
289		}
290		windowMinutes, ok := intFromRaw(obj["window_minutes"])
291		if !ok || windowMinutes <= 0 {
292			return harnesses.QuotaWindow{}, false
293		}
294		usedPercent, ok := floatFromRaw(obj["used_percent"])
295		if !ok {
296			return harnesses.QuotaWindow{}, false
297		}
298		window := harnesses.QuotaWindow{
299			Name:          codexQuotaWindowName(windowMinutes),
300			LimitID:       stringFromRaw(obj["limit_id"]),
301			LimitName:     stringFromRaw(obj["limit_name"]),
302			WindowMinutes: windowMinutes,
303			UsedPercent:   usedPercent,
304			State:         harnesses.QuotaStateFromUsedPercent(int(usedPercent)),
305		}
306		if resetsAt, ok := int64FromRaw(obj["resets_at"]); ok && resetsAt > 0 {
307			window.ResetsAtUnix = resetsAt
308			window.ResetsAt = time.Unix(resetsAt, 0).UTC().Format(time.RFC3339)
309		}
310		return window, true
311	}
312	
313	func codexQuotaWindowName(minutes int) string {
314		if minutes%(24*60) == 0 {
315			return fmt.Sprintf("%dd", minutes/(24*60))
316		}
317		if minutes%60 == 0 {
318			return fmt.Sprintf("%dh", minutes/60)
319		}
320		return fmt.Sprintf("%dm", minutes)
321	}
