86	// RunQuotaHarnessConformance asserts the QuotaHarness contract.
87	//
88	//   - The base Harness contract via RunHarnessConformance.
89	//   - QuotaStatus returns a valid value (no error) for a cold cache.
90	//   - QuotaFreshness is positive.
91	//   - SupportedLimitIDs is callable and stable (two calls return the
92	//     same multiset).
93	//   - RefreshQuota returns without error and the emitted
94	//     Windows[].LimitID is a subset of SupportedLimitIDs().
95	//   - Concurrent RefreshQuota calls all return without error and share
96	//     a consistent post-state (single-flight contract shape; exact
97	//     probe count is NOT asserted here — that belongs to harness-local
98	//     tests, e.g. the synthetic's probe counter).
99	func RunQuotaHarnessConformance(t *testing.T, h harnesses.QuotaHarness) {
100		t.Helper()
101		if h == nil {
102			t.Fatal("RunQuotaHarnessConformance called with nil harness")
103		}
104	
105		RunHarnessConformance(t, h)
106	
107		t.Run("QuotaFreshnessPositive", func(t *testing.T) {
108			if got := h.QuotaFreshness(); got <= 0 {
109				t.Errorf("QuotaFreshness() = %v, want > 0", got)
110			}
111		})
112	
113		t.Run("SupportedLimitIDsStable", func(t *testing.T) {
114			a := h.SupportedLimitIDs()
115			b := h.SupportedLimitIDs()
116			if !stringSetEqual(a, b) {
117				t.Errorf("SupportedLimitIDs not stable: first=%v second=%v", a, b)
118			}
119		})
120	
121		t.Run("QuotaStatusReturnsValue", func(t *testing.T) {
122			ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
123			defer cancel()
124			if _, err := h.QuotaStatus(ctx, time.Now()); err != nil {
125				t.Errorf("QuotaStatus returned error %v; absence of evidence MUST be reported via QuotaStateValue, not error", err)
126			}
127		})
128	
129		t.Run("RefreshQuotaWindowsLimitIDSubset", func(t *testing.T) {
130			ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
131			defer cancel()
132			status, err := h.RefreshQuota(ctx)
133			if err != nil {
134				// Probe failure MUST be reported as QuotaStateValue, not error.
135				t.Errorf("RefreshQuota returned error %v; probe failure MUST be reported via QuotaStateValue", err)
136				return
137			}
138			supported := stringSet(h.SupportedLimitIDs())
139			for i, w := range status.Windows {
140				if w.LimitID == "" {
141					continue
142				}
143				if _, ok := supported[w.LimitID]; !ok {
144					t.Errorf("RefreshQuota Windows[%d].LimitID = %q is not in SupportedLimitIDs() = %v", i, w.LimitID, h.SupportedLimitIDs())
145				}
146			}
147		})
148	
149		t.Run("RefreshQuotaSingleFlightShape", func(t *testing.T) {
150			const N = 8
151			ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
152			defer cancel()
153	
154			var (
155				wg      sync.WaitGroup
156				mu      sync.Mutex
157				results []harnesses.QuotaStatus
158				errs    []error
159			)
160			wg.Add(N)
161			for i := 0; i < N; i++ {
162				go func() {
163					defer wg.Done()
164					s, err := h.RefreshQuota(ctx)
165					mu.Lock()
166					results = append(results, s)
167					errs = append(errs, err)
168					mu.Unlock()
169				}()
170			}
171			wg.Wait()
172	
173			for i, err := range errs {
174				if err != nil {
175					t.Errorf("concurrent RefreshQuota[%d] returned error %v; expected nil", i, err)
176				}
177			}
178			// Post-state consistency: a final QuotaStatus read MUST be a
179			// valid value (no error). The conformance suite does not
180			// pin individual field values, only the contract shape.
181			if _, err := h.QuotaStatus(ctx, time.Now()); err != nil {
182				t.Errorf("QuotaStatus after concurrent RefreshQuota returned error %v", err)
183			}
184		})
185	}
